import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Grid,
  Paper,
  Typography,
  Tabs,
  Tab,
  CircularProgress,
  Alert,
  Avatar,
  Button
} from '@mui/material';
import { useAuth } from '../../contexts/AuthContext';
import ProjectsManager from './ProjectsManager';
import CertificatesManager from './CertificatesManager';
import PublicationsManager from './PublicationsManager';
import BlogManager from './BlogManager';

const Dashboard = () => {
  const { user } = useAuth();
  const [currentTab, setCurrentTab] = useState(0);
  const [photo, setPhoto] = useState(localStorage.getItem('adminPhoto') || '');

  useEffect(() => {
    // Update localStorage when photo changes
    if (photo) {
      localStorage.setItem('adminPhoto', photo);
    }
  }, [photo]);

  const handlePhotoChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhoto(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  if (!user || user.role !== 'admin') {
    return (
      <Container>
        <Alert severity="error">
          Access denied. You must be an admin to view this page.
        </Alert>
      </Container>
    );
  }

  const handleTabChange = (event, newValue) => {
    setCurrentTab(newValue);
  };

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Grid container spacing={3}>
        <Grid item xs={12}>
          <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
            <Avatar
              src={photo || '/profile-photo.jpg'}
              alt="Admin Photo"
              sx={{ width: 120, height: 120, mb: 2, boxShadow: 2, border: '3px solid #1976d2' }}
            />
            <Button variant="outlined" component="label" sx={{ mb: 2 }}>
              Upload Photo
              <input type="file" accept="image/*" hidden onChange={handlePhotoChange} />
            </Button>
            <Typography variant="h4" gutterBottom>
              Welcome, {user.username}!
            </Typography>
            <Typography variant="body1" color="text.secondary" paragraph>
              Manage your portfolio content from this dashboard.
            </Typography>
          </Paper>
        </Grid>
        <Grid item xs={12}>
          <Paper sx={{ width: '100%' }}>
            <Tabs
              value={currentTab}
              onChange={handleTabChange}
              indicatorColor="primary"
              textColor="primary"
              variant="scrollable"
              scrollButtons="auto"
            >
              <Tab label="Projects" />
              <Tab label="Certificates" />
              <Tab label="Publications" />
              <Tab label="Blog Posts" />
            </Tabs>
            <Box sx={{ p: 3 }}>
              {currentTab === 0 && <ProjectsManager />}
              {currentTab === 1 && <CertificatesManager />}
              {currentTab === 2 && <PublicationsManager />}
              {currentTab === 3 && <BlogManager />}
            </Box>
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default Dashboard;
